urlset:
{# Home page #}

  {{ site.url }}/
  daily
  1.0


{# Published posts #}
{% for post in all_posts %}

  {{ post.url }}
  {% if post.updated_at %}
  {{ post.updated_at | date_format(format="%Y-%m-%d") }}
  {% elif post.published_at %}
  {{ post.published_at | date_format(format="%Y-%m-%d") }}
  {% endif %}
  weekly
  0.8

{% endfor %}

{# Published pages #}
{% for page in all_pages %}

  {{ page.url }}
  {% if page.updated_at %}
  {{ page.updated_at | date_format(format="%Y-%m-%d") }}
  {% endif %}
  monthly
  0.6

{% endfor %}
